import React, { useState } from "react";
import {
  Container,
  Paper,
  TextField,
  Button,
  Typography,
  Box,
  Tab,
  Tabs,
  Alert,
} from "@mui/material";
import { useDispatch } from "react-redux";
import { useNavigate } from "react-router-dom";
import { setCredentials } from "../store/authSlice";
import { login, register } from "../services/api";

const LoginPage = () => {
  const dispatch = useDispatch();
  const navigate = useNavigate();
  const [tabValue, setTabValue] = useState(0);
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);
  const [formData, setFormData] = useState({
    email: "",
    password: "",
    full_name: "",
    phone: "",
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
    setError("");
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError("");

    try {
      let response;
      if (tabValue === 0) {
        // ąÆčģč¢ą┤
        response = await login(formData.email, formData.password);
      } else {
        // ąĀąĄčöčüčéčĆą░čåč¢čÅ
        if (!formData.full_name) {
          setError("ąæčāą┤čī ą╗ą░čüą║ą░, ą▓ą║ą░ąČč¢čéčī ą▓ą░čłąĄ č¢ą╝'čÅ");
          setLoading(false);
          return;
        }
        response = await register(formData);
      }

      dispatch(setCredentials(response));
      navigate("/");
    } catch (err) {
      setError(err.response?.data?.error || "ąĪčéą░ą╗ą░čüčÅ ą┐ąŠą╝ąĖą╗ą║ą░");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm" sx={{ py: 8 }}>
      <Paper elevation={3} sx={{ p: 4 }}>
        <Typography variant="h4" component="h1" textAlign="center" gutterBottom>
          BUYTIRE
        </Typography>

        <Tabs
          value={tabValue}
          onChange={(e, v) => setTabValue(v)}
          sx={{ mb: 3 }}
        >
          <Tab label="ąÆčģč¢ą┤" />
          <Tab label="ąĀąĄčöčüčéčĆą░čåč¢čÅ" />
        </Tabs>

        {error && (
          <Alert severity="error" sx={{ mb: 2 }}>
            {error}
          </Alert>
        )}

        <form onSubmit={handleSubmit}>
          {tabValue === 1 && (
            <>
              <TextField
                fullWidth
                label="ą¤ąŠą▓ąĮąĄ č¢ą╝'čÅ"
                name="full_name"
                value={formData.full_name}
                onChange={handleChange}
                margin="normal"
                required
              />
              <TextField
                fullWidth
                label="ąóąĄą╗ąĄčäąŠąĮ"
                name="phone"
                value={formData.phone}
                onChange={handleChange}
                margin="normal"
              />
            </>
          )}

          <TextField
            fullWidth
            label="Email"
            name="email"
            type="email"
            value={formData.email}
            onChange={handleChange}
            margin="normal"
            required
          />

          <TextField
            fullWidth
            label="ą¤ą░čĆąŠą╗čī"
            name="password"
            type="password"
            value={formData.password}
            onChange={handleChange}
            margin="normal"
            required
          />

          <Button
            type="submit"
            fullWidth
            variant="contained"
            size="large"
            disabled={loading}
            sx={{ mt: 3 }}
          >
            {loading
              ? "ąŚą░ą▓ą░ąĮčéą░ąČąĄąĮąĮčÅ..."
              : tabValue === 0
                ? "ąŻą▓č¢ą╣čéąĖ"
                : "ąŚą░čĆąĄčöčüčéčĆčāą▓ą░čéąĖčüčÅ"}
          </Button>
        </form>
      </Paper>
    </Container>
  );
};

export default LoginPage;
